# -*- coding: utf-8 -*-
"""Крутилки ведения позиции V8.1 (docs/04 §3, docs/01 §2). Совпадают с движком-эталоном."""
from ._env import env_float, env_str, env_bool

# Три лимит-ноги (фибо-уровни от A->B) и общий стоп.
FIB_ENTRIES = [0.382, 0.5, 0.618]
# 🎛 рантайм-крутилка (дашборд «Настройки», ADR 0009/0004). Дефолт 1.0 = ПРОВЕРЕНО;
# 0.9 (старый бот) — худший по Calmar; любое ≠1.0 — вне честных OOS-чисел (нужен ре-бэктест).
STOP_FIB = env_float("STOP_FIB", 1.0)
# 🎛 тип триггера стоп-лосса (дашборд «Настройки», ADR 0007/0009). Дефолт LastPrice = паритет
# с бэктестом (эталон видит цену сделок, свечной low); MarkPrice устойчивее к шип-стоп-хантам,
# но даёт небольшое расхождение с эталоном (parity). Допустимо: LastPrice/MarkPrice/IndexPrice.
SL_TRIGGER_BY = env_str("SL_TRIGGER_BY", "LastPrice")

# Машина выходов.
COMMIT_LV = 0.5         # нога, коммитящая сетап (после заливки 0.5 — committed)
# 🎛 рантайм-крутилка (дашборд «Настройки», ADR 0015/0009): цель ноги-бегунка 0.5 = ext(LEG2_EXT) = B + LEG2_EXT*R.
# Дефолт 1.0 = 2.0R = ПРОВЕРЕНО (чемпион); любое ≠1.0 — вне честных OOS-чисел (ре-бэктест перед реалом, как STOP_FIB).
LEG2_EXT = env_float("LEG2_EXT", 1.0)   # бегунок ноги 0.5: цель ext(1.0) = B + 1.0*R (= 2.0)
LEG3_MODE = "0.382"     # нога 0.618 — близкий выход на fib 0.382
NEXT_SCALP = {0.382: 0.236, 0.5: 0.382}  # защитные скальпы для не самых глубоких ног

# Таймаут от commit — в ЗАКРЫТЫХ 4h-барах (не 15m-тиках).
TIMEOUT_BARS = 72

# Причинность на 15m (фиксы look-ahead).
CAUSAL_REANCHOR = True   # суб-бар-заливы проверяются ДО пере-якоря (#4)
NO_SAME_SUBBAR_TP = True # не брать TP в том же суб-баре, что и залив

# 🎛 v3-режим (дашборд «Настройки»): пере-якорь ПОСЛЕ закрытого скальпа 0.382 — на новый хай до commit
# перерисовать сетку и ПЕРЕЗАРЯДИТЬ отскальпленную ногу. Дефолт False = v2 (эталон: якорь замерзает на
# первом заливе, инвариант #9). ON = v3 (research R6; demo-first, реал позже малым). Паритет: движок ⇄ live
# считают ТЕМ ЖЕ флагом (reanchor_after_scalp в run_v8 / on_bar_close).
REANCHOR_AFTER_SCALP = env_bool("REANCHOR_AFTER_SCALP", False)

# 🎛 фикс «живой бегунок» (дашборд «Настройки», ADR 0015): держит ногу-бегунок 0.5 без резтинг-TP 0.236 в
# до-профитной фазе (чинит «два reduce-only TP на 0.236 бьют разом → бегунок гибнет»). Дефолт False = бит-в-бит.
# LIVE-ONLY (движок не трогаем); пробрасывается ПАРАМЕТРОМ в lifecycle (не config-direct — иначе тумблер мёртв).
RUNNER_TP_HOLD = env_bool("RUNNER_TP_HOLD", False)

# 🎛 двойной заход 4–5% (дашборд «Настройки», ADR 0016; задача 5.9): после закрытого скальпа 0.382 нога 0.5
# перезаходит с допуском tol*|B−A| (полоса цен, ловит near-miss). Дефолт OFF = бит-в-бит v2 (движок double-dip
# инертен при cond05=None). ON = вне честных чисел (walk-forward слабый 5–6/8) → demo-first, реал позже малым.
# Флаг маппится bool→cond05='double_dip'|None в _poll_tick; движок ⇄ live считают ТЕМ ЖЕ cond05/tol05 (паритет).
DOUBLE_DIP_ENABLED = env_bool("DOUBLE_DIP_ENABLED", False)
DOUBLE_DIP_TOL = env_float("DOUBLE_DIP_TOL", 0.04)   # % допуска высоты импульса |B−A| (0.0–0.10); рабочая точка 0.04

# 🎛 R8-трейл бегунка (дашборд «Настройки», ADR 00XX; путь Y = НАТИВНЫЙ трейлер Bybit, дизайн A). При ON:
# соло-бегунок за вершиной B ведётся биржевым trailing-стопом (дистанция TRAIL_R·(B−A)) ПОВЕРХ вшитого стопа
# (дизайн A — не заменяет БУ/Full, а добавляет пол = движковый max(estop,trail)); фикс-цель бегунка снимается
# (родня RUNNER_TP_HOLD). Дефолт OFF = трейлер НЕ ставится = бит-в-бит. Тик-уровень биржи ≠ 15m-бэктест →
# вне честных чисел (форвард-замер на demo); активация — отдельное go/no-go после форварда.
TRAIL_ENABLED = env_bool("TRAIL_ENABLED", False)
TRAIL_R = env_float("TRAIL_R", 0.4)   # ширина трейла в R = TRAIL_R·(B−A); 0.4 = центр проверенного плато 0.35–0.55

# Издержки (для теневого движка / сверки; реальную комиссию даст биржа).
FEE_PCT = 0.04
SLIPPAGE_PCT = 0.02
